'use strict';

/*
  Host-side half of the plugin bridge, shared by main.js and settings.js. Creates
  the single sandboxed iframe for the page, seeds it with theme data, asks it to
  run each plugin view, and services the privileged requests the sandbox can't
  perform itself (network, chrome.storage cache, chrome.tabs, button actions,
  toasts, fade). View rendering and the activity stack live inside the iframe.
*/

import {
  SANDBOX_READY, REGISTER_ACTION, ACTIVITY_STATE, NET_FETCH, CACHE_GET, CACHE_SET,
  OPEN_TAB, TOAST, FADE_CONFIG, FADE_ACTIVITY, FADE_FEATURED, RUN_DONE, SEED, RUN,
  ACTION_INVOKE, POP_REQUEST, NET_RESULT, CACHE_RESULT, buildActionUri
} from 'plugin-bridge';
import {registerPluginAction} from 'actions';

const CACHE_PREFIX = 'pluginCache:';

let iframe = null;
let options = {};
let ready = false;
const outbox = [];                 // RUN messages queued until the iframe is ready
const runResolvers = new Map();    // `${plugin}|${view}` -> resolve

function toSandbox(message) {
  if (ready) iframe.contentWindow.postMessage(message, '*');
  else outbox.push(message);
}

function currentSeed() {
  const dynamic = document.getElementById('dynamic-colors');
  return {
    type: SEED,
    themes: window.stored.themes,
    currentThemeIdx: window.stored.currentThemeIdx,
    themeCss: dynamic ? dynamic.innerText : ''
  };
}

function handleNetFetch(msg) {
  // NB: no async/await here — host code is compiled by the ES5 minifier pipeline.
  fetch(msg.url, msg.options).then(resp => {
    const ok = resp.ok;
    const status = resp.status;
    return resp.text().then(text => {
      let body = text;
      if (msg.dataType === 'json') {
        try { body = JSON.parse(text); } catch (err) { /* leave as text */ }
      }
      iframe.contentWindow.postMessage({type: NET_RESULT, reqId: msg.reqId, ok, status, body}, '*');
    });
  }).catch(err => {
    iframe.contentWindow.postMessage({type: NET_RESULT, reqId: msg.reqId, ok: false, status: 0, body: String(err)}, '*');
  });
}

function onMessage(event) {
  if (!iframe || event.source !== iframe.contentWindow) return;
  const msg = event.data || {};
  switch (msg.type) {
    case SANDBOX_READY:
      ready = true;
      iframe.contentWindow.postMessage(currentSeed(), '*');
      outbox.forEach(m => iframe.contentWindow.postMessage(m, '*'));
      outbox.length = 0;
      break;
    case RUN_DONE: {
      const resolve = runResolvers.get(`${msg.plugin}|${msg.view}`);
      if (resolve) { runResolvers.delete(`${msg.plugin}|${msg.view}`); resolve(); }
      break;
    }
    case REGISTER_ACTION: {
      const uri = buildActionUri(msg.pluginName, msg.actionPathname);
      registerPluginAction(msg.displayName, uri, () => toSandbox({type: ACTION_INVOKE, uri}));
      break;
    }
    case ACTIVITY_STATE:
      if (options.onActivityState) options.onActivityState(msg.title, msg.canGoBack);
      break;
    case NET_FETCH:
      handleNetFetch(msg);
      break;
    case CACHE_GET:
      chrome.storage.local.get(CACHE_PREFIX + msg.key, items => {
        const value = items[CACHE_PREFIX + msg.key];
        iframe.contentWindow.postMessage(
          {type: CACHE_RESULT, reqId: msg.reqId, value: value === undefined ? null : value}, '*');
      });
      break;
    case CACHE_SET:
      chrome.storage.local.set({[CACHE_PREFIX + msg.key]: msg.value});
      break;
    case OPEN_TAB:
      chrome.tabs.create({url: msg.url, active: msg.active !== false});
      break;
    case TOAST:
      window.Materialize.toast(window.$(`<span>${msg.text}</span>`), window.SHORT_DURATION_MS);
      break;
    case FADE_CONFIG:
      if (options.onFadeConfig) options.onFadeConfig(msg);
      break;
    case FADE_ACTIVITY:
      if (options.onFadeActivity) options.onFadeActivity();
      break;
    case FADE_FEATURED:
      if (options.onFadeFeatured) options.onFadeFeatured(msg.html);
      break;
    default:
      break;
  }
}

const PluginHost = {
  /*
    opts:
      frameHost      element the sandbox iframe is appended into
      onActivityState(title, canGoBack)  called when the in-iframe activity changes (main page)
      onFadeConfig(cfg)                  called when a plugin configures the fade overlay (main page)
  */
  init(opts) {
    options = opts;
    iframe = document.createElement('iframe');
    iframe.id = 'plugin-frame';
    iframe.setAttribute('src', '/sandbox.html');
    window.addEventListener('message', onMessage);
    opts.frameHost.appendChild(iframe);
  },
  // Run each `view` for each plugin, in the given order. Resolves once every
  // requested view has finished executing in the sandbox.
  run(pluginList, views) {
    const promises = [];
    pluginList.forEach(plugin => views.forEach(view => {
      promises.push(new Promise(resolve => runResolvers.set(`${plugin.name}|${view}`, resolve)));
      toSandbox({type: RUN, plugin, view});
    }));
    return Promise.all(promises);
  },
  // Ask the sandbox to pop the current activity (host back button pressed).
  requestBack() {
    toSandbox({type: POP_REQUEST});
  }
};

export default PluginHost;
